Vue.prototype.isLogin=function() {
  if (!this.$store.state.phone) {
    Dialog.confirm({
      title: "需要登录",
      message: "请登录您的账号",
    })
      .then(() => {
        // on confirm
        this.$router.push("/my/login");
      })
      .catch(() => {
        // on cancel
      });
    return false;
  }else{
    return true
  }
}
// 定义全局vue过滤器, 需要放在vue实例化之前,跟注册全局组件一样
Vue.filter('formatDate', function (time) {
  let date = new Date(time);
  let Y = date.getFullYear();
  let M = date.getMonth() + 1;
  let D = date.getDate();

  Y = Y < 10 ? "0" + Y : Y;
  D = D < 10 ? "0" + D : D;
  return `${Y}-${M}-${D}`;
})

