import axios from "axios";
import { Dialog } from "vant";
import store from '../store/index'

// let flag='dev'

// let baseUrl='http://132.232.87.95:3003/'


// if(flag==='dev') baseUrl='http://localhost:8000/api'
let baseUrl=process.env.VUE_APP_URL

const get =(url,data)=>{
    let token=store.state.token
    return  new Promise((resolve,reject)=>{
        axios.get(baseUrl+url,{params:data,headers:{'user-token':token}}).then(res=>{
            if(res.data.code==666) resolve(res.data)
            else Dialog({message:res.data.msg})
        }).catch(err=>Dialog({message:'网络请求失败,请重试'}))
    })
}
const post=(url,data)=>{
    let token=store.state.token
    return new Promise((resolve,reject)=>{
        axios.post(baseUrl+url,data,{headers:{'user-token':token}}).then(res=>{
            if(res.data.code==666) resolve(res.data)
            else{
                // Dialog({message:res.data.msg})
                Dialog({message:res.data.msg})

            }
        }).catch(err=>Dialog({message:'网络请求失败,请重试'}))
    })
}
export default{
    get,post
}