<template>
  <div id="app">
    
    <router-view></router-view>
    <Footer></Footer>
  </div>
</template>
<style lang="less">
@import 'vant/lib/index.less';

html,body,#app{
  height: 100%;
}
.main{
  padding-bottom: 50px;
}
#app{
  .van-nav-bar .van-icon,.van-nav-bar__text{
    color: @red;
  }
}
</style>

<script>
import $axios from '@/utils/index'

export default {
  name: 'App',
  components: {
   
    
  },
  methods: {
    async getCartNum(){
      if(!this.isLogin) return false
      try {
        let res= await $axios.get('cart/all')
        // console.log(res)
        let sum=0
        res.list.forEach(item=>{
          sum+=item.buyNum
        })
        // console.log(sum)
        this.$store.commit('setNum',sum)
        // console.log(this.$store.state.cart.cartNum)
      } catch (err) {
        console.log(err)
      }
    }
  },
  created(){
    this.getCartNum()
  }
}
</script>

