import Vue from 'vue';
import Router from 'vue-router';
Vue.use(Router)

export default new Router({
    // mode:'history',
    routes:[
        {
            path:'/',
            redirect:'/product'
        },
        {
            path:'/product',
            component: ()=> import('@/views/product/index'),
            redirect: '/product/list',
            children:[
                {
                    path:'list',
                    component:()=>import('@/views/product/children/list')
                },
                {
                    path:'detail/:productId',
                    name:'detail',
                    component:()=>import('@/views/product/children/detail')
                },
            ]
        },
        {
            path:'/classify',
            component: ()=> import('@/views/classify/index')
        },
        {
            path:'/cart',
            component: ()=> import('@/views/cart/index')
        },
        {
            path:'/preOrder',
            name:'preOrder',
            component: ()=> import('@/views/preOrder/index')
        },
        {
            path:'/pay',
            name:'pay',
            component: ()=> import('@/views/pay/index')
        },
        {
            path:'/order',
            name:'order',
            redirect:'/order/list',
            component: ()=> import('@/views/order/index'),
            children:[
                {
                    path:'list',
                    name:'orderList',
                    component:()=>import('@/views/order/children/list')
                },
                {
                    path:'detail/:orderId',
                    
                    component:()=>import('@/views/order/children/detail')
                },
            ]
        },
        {
            path:'/address',
            name:'address',
            redirect:'/address/list',
            component: ()=> import('@/views/address/index'),
            children:[
                {
                    path:'list',
                    name:'addressList',
                    component:()=>import('@/views/address/children/list')
                },
                {
                    path:'edit/:addressId',
                    
                    component:()=>import('@/views/address/children/edit')
                },
                {
                    path:'add',
                    
                    component:()=>import('@/views/address/children/add')
                },
            ]
        },
        {
            path:'/my',
            name:'my',
            redirect:'/my/person',
            component: ()=> import('@/views/my/index'),
            children:[
                {
                    path:'person',
                    component:()=>import('@/views/my/children/person')
                },
                {
                    path:'login',
                    name:'login',
                    component:()=>import('@/views/my/children/login')
                },
                {
                    path:'setting',
                    name:'setting',
                    component:()=>import('@/views/my/children/setting')
                }
            ]
        },
        {
            path:'/demo',
            component:()=> import('@/components/Demo')
        },
        {
            path:'*',
            component: ()=>import('@/components/NotFound')
        }
        
    ],
    scrollBehavior(to, from, savedPosition) { // 解决vue页面之间跳转，页面不是在顶部的问题
        return {
            x: 0,
            y: 0
        }
    }
})